 * Returns -1 if no such element exists.
 * Assumes nums is strictly increasing.
 */
function find_last_le(nums, l, r, X) {
    let low = l;
    let high = r;
    let result = -1;

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        if (nums[mid] <= X) {
            result = mid;
            low = mid + 1; // Try to find an even larger index
        } else {
            high = mid - 1; // nums[mid] is too large
        }
    }
    return result;
}

function solve(nums, queries) {
    const N = nums.length;

    // Step 1: Preprocessing - Prefix sums of even numbers
    // P[i] stores the count of even numbers in nums[0...i-1]
    const P = new Array(N + 1).fill(0);
    for (let i = 0; i < N; i++) {
        P[i + 1] = P[i] + (nums[i] % 2 === 0 ? 1 : 0);
    }

    const results = [];

    // Helper check function for binary search
    // Checks if the k-th remaining even number is less than or equal to X.
    const check = (X, l, r, k) => {
        // 1. Find j_max: The index of the last element in nums[l..r] <= X
        const j_max = find_last_le(nums, l, r, X);

        // 2. Calculate C(X): Count of removed even numbers <= X
        let C_X = 0;
        if (j_max >= l) {
            // Count of evens in nums[l...j_max]
            C_X = P[j_max + 1] - P[l];
        }

        // 3. Rank calculation:
        // Total evens <= X is floor(X/2)
        const total_evens = Math.floor(X / 2);

        // Rank in E' = Total evens - Removed evens
        const rank = total_evens - C_X;

        return rank >= k;
    };

    // Step 2: Process Queries
    for (const [l, r, k] of queries) {
        // Binary search for the answer X.

        // L: Smallest possible answer (2) or 2k if no removals.
        // Since k >= 1, L starts at 2.
        let L = 2; 

        // R: A sufficiently large upper bound. k <= 10^9. Max removed count is 10^5.
        // Max answer X is roughly 2k + N. We use a generous bound that fits in JS number type.
        // 3 * 10^14 is very safe.
        let R = 3e14; 

        let ansX = R;

        while (L <= R) {
            // Use Math.floor for M calculation
            let M = Math.floor((L + R) / 2);

            if (check(M, l, r, k)) {
                ansX = M;
                R = M - 1; // Try to find a smaller answer
            } else {
                L = M + 1; // Need a larger answer
            }
